//! Board widget — renders the full board layout with title bar, columns, and status bar.

use ratatui::layout::{Constraint, Direction, Layout, Rect};
use ratatui::style::{Color, Modifier, Style};
use ratatui::text::{Span, Text};
use ratatui::widgets::{Block, Borders, Paragraph};

use crate::core::Task;
use crate::tui::app::{App, Mode};

use super::card::render_task_card;
use super::dialog::{render_confirm_overlay, render_edit_overlay, render_insert_overlay};
use super::help::render_help_overlay;

/// Render the full board view with columns, task cards, title bar, and status bar.
pub fn render_board(frame: &mut ratatui::Frame<'_>, app: &mut App) {
    let area = frame.area();

    let vertical = Layout::default()
        .direction(Direction::Vertical)
        .constraints([Constraint::Length(1), Constraint::Fill(1), Constraint::Length(1)])
        .split(area);

    render_title_bar(frame, vertical[0], app);

    let content = vertical[1];
    match app.mode {
        Mode::Help => render_help_overlay(frame, content),
        Mode::Insert => render_insert_overlay(frame, content, app),
        Mode::Edit => render_edit_overlay(frame, content, app),
        Mode::Confirm => render_confirm_overlay(frame, content, app),
        _ => render_column_panels(frame, content, app),
    }

    render_status_bar(frame, vertical[2], app);
}

fn render_title_bar(frame: &mut ratatui::Frame<'_>, area: Rect, app: &App) {
    let board_name = app
        .state
        .as_ref()
        .map(|s| s.board.name.as_str())
        .unwrap_or("Kanban");
    let text = format!(" {} ", board_name);
    let paragraph = Paragraph::new(Text::from(text)).style(
        Style::default()
            .fg(Color::White)
            .bg(Color::Blue)
            .add_modifier(Modifier::BOLD),
    );
    frame.render_widget(paragraph, area);
}

fn render_status_bar(frame: &mut ratatui::Frame<'_>, area: Rect, app: &App) {
    let text = if let Some(ref err) = app.error {
        err.clone()
    } else {
        match app.mode {
            Mode::Normal => "h/l col | j/k task | a add | e edit | m move | d del | H/L move-task | J/K reorder | C col-mode | ? help | q quit".to_string(),
            Mode::Move => "MOVE MODE — h/l target col | Enter confirm | Esc cancel".to_string(),
            Mode::Column => "COLUMN MODE — a add | r rename | d delete | h/l reorder | Esc exit".to_string(),
            Mode::Insert => "INSERT — Enter save | Esc cancel".to_string(),
            Mode::Edit => "EDIT — Enter save | Esc cancel | Tab cycle field".to_string(),
            Mode::Confirm => "CONFIRM — y/N".to_string(),
            Mode::Help => "?/Esc/q close".to_string(),
        }
    };

    let style = if app.error.is_some() {
        Style::default().fg(Color::Red)
    } else {
        Style::default().fg(Color::Gray)
    };

    let paragraph = Paragraph::new(Text::from(text)).style(style);
    frame.render_widget(paragraph, area);
}

/// Render the column panels (normal/move/column mode).
pub fn render_column_panels(frame: &mut ratatui::Frame<'_>, area: Rect, app: &App) {
    let state = match &app.state {
        Some(s) => s,
        None => {
            let text = "No board loaded";
            let paragraph = Paragraph::new(Text::from(text));
            frame.render_widget(paragraph, area);
            return;
        }
    };

    let num_cols = state.columns.len();
    if num_cols == 0 {
        let text = "No columns";
        let paragraph = Paragraph::new(Text::from(text));
        frame.render_widget(paragraph, area);
        return;
    }

    let constraints: Vec<Constraint> =
        std::iter::repeat_n(Constraint::Percentage(100 / num_cols as u16), num_cols).collect();
    let col_areas = Layout::default()
        .direction(Direction::Horizontal)
        .constraints(constraints)
        .split(area);

    for (col_idx, (col, col_area)) in state.columns.iter().zip(col_areas.iter()).enumerate() {
        let tasks: Vec<&Task> = state
            .tasks
            .iter()
            .filter(|t| t.column_id == col.id)
            .collect();

        let is_focused_col = col_idx == app.focused_col_idx;
        let is_move_target =
            app.mode == Mode::Move && col_idx == app.move_target_col_idx && col_idx != app.focused_col_idx;

        let col_block_style = if is_move_target {
            Style::default()
                .fg(Color::Yellow)
                .bg(Color::DarkGray)
                .add_modifier(Modifier::BOLD)
        } else if is_focused_col {
            Style::default()
                .fg(Color::White)
                .bg(Color::DarkGray)
                .add_modifier(Modifier::BOLD)
        } else {
            Style::default().fg(Color::Gray).bg(Color::Reset)
        };

        let block = Block::default()
            .borders(Borders::ALL)
            .title(Span::raw(&col.name))
            .style(col_block_style);
        frame.render_widget(&block, *col_area);

        let inner = block.inner(*col_area);

        if tasks.is_empty() {
            let empty_text = Paragraph::new(Text::from("  (empty)"));
            frame.render_widget(empty_text, inner);
            continue;
        }

        let card_height: u16 = 2;
        let available_height = inner.height as usize;
        let card_height_usize = card_height as usize;
        let max_visible = available_height.saturating_sub(1) / card_height_usize;

        let focused_idx = if is_focused_col {
            app.focused_task_idx
        } else {
            0
        };
        let visible_tasks = tasks
            .iter()
            .cloned()
            .enumerate()
            .skip_while(|(i, _)| *i + max_visible <= focused_idx)
            .take(max_visible)
            .map(|(_, t)| t)
            .collect::<Vec<_>>();

        let mut y_offset: u16 = 0;
        for (task_idx, task) in visible_tasks.iter().enumerate() {
            let actual_idx = if focused_idx >= max_visible {
                focused_idx - max_visible + task_idx
            } else {
                task_idx
            };
            let is_selected = is_focused_col && actual_idx == app.focused_task_idx;

            let remaining_height = inner.height.saturating_sub(y_offset);
            let card_area = Rect {
                x: inner.x,
                y: inner.y + y_offset,
                width: inner.width,
                height: card_height.min(remaining_height),
            };

            if card_area.height < 2 || card_area.width < 1 {
                break;
            }

            render_task_card(frame, app, task, is_selected, card_area);

            y_offset += card_height;
            if y_offset >= inner.height {
                break;
            }
        }
    }
}

//! Card widget — renders individual task cards with jj-style short IDs.

use ratatui::layout::Rect;
use ratatui::style::{Color, Modifier, Style};
use ratatui::text::{Line, Span, Text};
use ratatui::widgets::Paragraph;

use crate::tui::app::App;
use crate::tui::render::{get_min_prefix_lengths, render_task_id_spans};

/// Render a single task card in the given area.
pub fn render_task_card(
    frame: &mut ratatui::Frame<'_>,
    app: &App,
    task: &crate::core::Task,
    is_selected: bool,
    area: Rect,
) {
    let card_style = if is_selected {
        Style::default()
            .add_modifier(Modifier::REVERSED)
            .fg(Color::Cyan)
    } else {
        Style::default()
    };

    let prio_name = app
        .state
        .as_ref()
        .and_then(|s| {
            s.priorities
                .iter()
                .find(|p| p.id == task.priority_id)
                .map(|p| p.name.as_str())
        })
        .unwrap_or("?");

    let prefix_lengths = get_min_prefix_lengths(app);
    let min_len = prefix_lengths.get(&task.id).copied().unwrap_or(1);
    let id_spans = render_task_id_spans(&task.id, min_len);

    let title_line = Line::from(Span::styled(format!("{}  ", task.title), card_style));

    let id_line = Line::from(
        id_spans
            .iter()
            .map(|s| Span::styled(s.content.clone(), s.style))
            .chain(std::iter::once(Span::styled(
                format!(" [{}]", prio_name),
                card_style,
            )))
            .collect::<Vec<_>>(),
    );

    let text = Text::from(vec![title_line, id_line]);
    let card = Paragraph::new(text);
    frame.render_widget(card, area);
}

//! Dialog widget — renders popup overlays for insert, edit, and confirm dialogs.

use ratatui::layout::Rect;
use ratatui::style::{Color, Modifier, Style};
use ratatui::text::{Line, Span, Text};
use ratatui::widgets::{Block, Borders, Paragraph};

use crate::tui::app::{ConfirmContext, App};

/// Render the insert task popup overlay.
pub fn render_insert_overlay(frame: &mut ratatui::Frame<'_>, area: Rect, app: &App) {
    let overlay_width = 40u16.min(area.width.saturating_sub(2));
    let overlay_height = 5u16.min(area.height.saturating_sub(2));
    let popup_area = Rect {
        x: (area.width - overlay_width) / 2,
        y: (area.height - overlay_height) / 2,
        width: overlay_width,
        height: overlay_height,
    };

    let block = Block::default()
        .borders(Borders::ALL)
        .title(" New Task Title ");

    let inner = block.inner(popup_area);
    frame.render_widget(block, popup_area);

    let lines = vec![
        Line::raw(""),
        Line::from(vec![
            Span::styled("Title: ", Style::default().fg(Color::Yellow)),
            Span::raw(&app.input_buffer),
            Span::raw("█"),
        ]),
        Line::raw(""),
        Line::raw("  Enter save | Esc cancel"),
        Line::raw(""),
    ];

    let paragraph = Paragraph::new(Text::from(lines));
    frame.render_widget(paragraph, inner);
}

/// Render the edit task popup overlay with field cycling.
pub fn render_edit_overlay(frame: &mut ratatui::Frame<'_>, area: Rect, app: &App) {
    let overlay_width = 50u16.min(area.width.saturating_sub(2));
    let overlay_height = 8u16.min(area.height.saturating_sub(2));
    let popup_area = Rect {
        x: (area.width - overlay_width) / 2,
        y: (area.height - overlay_height) / 2,
        width: overlay_width,
        height: overlay_height,
    };

    let block = Block::default().borders(Borders::ALL).title(" Edit Task ");

    let task = match &app.editing_task {
        Some(t) => t,
        None => {
            let paragraph = Paragraph::new(Text::from("No task to edit"));
            frame.render_widget(paragraph, popup_area);
            return;
        }
    };

    let state = match &app.state {
        Some(s) => s,
        None => {
            let paragraph = Paragraph::new(Text::from("No state"));
            frame.render_widget(paragraph, popup_area);
            return;
        }
    };

    let prio_name = state
        .priorities
        .iter()
        .find(|p| p.id == task.priority_id)
        .map(|p| p.name.as_str())
        .unwrap_or("?");

    let mut lines = vec![Line::raw("")];

    // Title
    let title_label = if app.edit_field == 0 {
        Style::default().fg(Color::Yellow).add_modifier(Modifier::BOLD)
    } else {
        Style::default()
    };
    lines.push(Line::from(vec![
        Span::styled("Title: ", title_label),
        Span::raw(if app.edit_field == 0 {
            &app.input_buffer
        } else {
            &task.title
        }),
        if app.edit_field == 0 { Span::raw("█") } else { Span::raw("") },
    ]));

    // Description
    let desc_label = if app.edit_field == 1 {
        Style::default().fg(Color::Yellow).add_modifier(Modifier::BOLD)
    } else {
        Style::default()
    };
    lines.push(Line::from(vec![
        Span::styled("Description: ", desc_label),
        Span::raw(if app.edit_field == 1 {
            &app.input_buffer
        } else {
            &task.description
        }),
        if app.edit_field == 1 { Span::raw("█") } else { Span::raw("") },
    ]));

    // Priority
    let prio_label = if app.edit_field == 2 {
        Style::default().fg(Color::Yellow).add_modifier(Modifier::BOLD)
    } else {
        Style::default()
    };
    lines.push(Line::from(vec![
        Span::styled("Priority: ", prio_label),
        Span::styled(
            format!("[{}]", prio_name),
            if app.edit_field == 2 {
                Style::default().add_modifier(Modifier::REVERSED)
            } else {
                Style::default()
            },
        ),
    ]));

    lines.push(Line::raw(""));
    lines.push(Line::raw("  Enter save | Esc cancel | Tab cycle | p priority"));
    lines.push(Line::raw(""));

    let paragraph = Paragraph::new(Text::from(lines));
    let inner = block.inner(popup_area);
    frame.render_widget(block, popup_area);
    frame.render_widget(paragraph, inner);
}

/// Render a confirmation dialog (y/N) for destructive actions.
pub fn render_confirm_overlay(frame: &mut ratatui::Frame<'_>, area: Rect, app: &App) {
    let overlay_width = 45u16.min(area.width.saturating_sub(2));
    let overlay_height = 5u16.min(area.height.saturating_sub(2));
    let popup_area = Rect {
        x: (area.width - overlay_width) / 2,
        y: (area.height - overlay_height) / 2,
        width: overlay_width,
        height: overlay_height,
    };

    let block = Block::default().borders(Borders::ALL).title(" Confirm ");

    let task = app.focused_task();
    let col = app.focused_column();
    let prompt = match app.confirm_context {
        Some(ConfirmContext::TaskDelete) => {
            if let Some(task) = task {
                format!("Delete task '{}' (y/N)?", task.title)
            } else {
                "Delete task (y/N)?".to_string()
            }
        }
        Some(ConfirmContext::ColumnDelete) => {
            if let Some(col) = col {
                let state = app.state.as_ref();
                let task_count = state
                    .map(|s| s.tasks.iter().filter(|t| t.column_id == col.id).count())
                    .unwrap_or(0);
                format!(
                    "Delete column '{}' ({} tasks)?\n  m=move-to-first  d=delete-all  n=cancel",
                    col.name, task_count
                )
            } else {
                "Delete column?\n  m=move-to-first  d=delete-all  n=cancel".to_string()
            }
        }
        None => {
            if let Some(task) = task {
                format!("Delete task '{}' (y/N)?", task.title)
            } else if let Some(_col) = col {
                "Delete column? (y/N)".to_string()
            } else {
                "Delete (y/N)?".to_string()
            }
        }
    };

    let lines: Vec<Line> = prompt
        .lines()
        .map(Line::from)
        .chain(std::iter::once(Line::raw("")))
        .collect();

    let inner = block.inner(popup_area);
    frame.render_widget(block, popup_area);
    frame.render_widget(Paragraph::new(Text::from(lines)), inner);
}

